import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const c=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1772600914000}'),s={name:"guide/getting-started.md"};function i(n,e,l,p,d,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>getbased is a blood work dashboard that turns your lab reports into interactive charts, trend analysis, and AI-powered interpretation. The app starts empty — your data is loaded by you, stored locally in your browser, and never uploaded anywhere by default.</p><h2 id="open-the-app" tabindex="-1">Open the App <a class="header-anchor" href="#open-the-app" aria-label="Permalink to &quot;Open the App&quot;">​</a></h2><p>The easiest way to get started is the hosted version at <strong><a href="https://getbased.health" target="_blank" rel="noreferrer">getbased.health</a></strong>. No installation required.</p><h3 id="self-host" tabindex="-1">Self-host <a class="header-anchor" href="#self-host" aria-label="Permalink to &quot;Self-host&quot;">​</a></h3><p>If you prefer to run it yourself, clone the repository and start a local server:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http.server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8000</span></span></code></pre></div><p>Then open <code>http://localhost:8000</code> in your browser. A local server is required because the app loads ES module scripts — opening <code>index.html</code> directly as a file will not work.</p><h2 id="install-as-a-pwa" tabindex="-1">Install as a PWA <a class="header-anchor" href="#install-as-a-pwa" aria-label="Permalink to &quot;Install as a PWA&quot;">​</a></h2><p>getbased is installable as a Progressive Web App on desktop and mobile. Look for the install prompt in your browser&#39;s address bar, or use your browser menu:</p><ul><li><strong>Chrome / Edge</strong>: address bar → install icon, or menu → &quot;Install getbased&quot;</li><li><strong>Safari (iOS)</strong>: Share → Add to Home Screen</li><li><strong>Firefox</strong>: menu → Install</li></ul><p>Once installed, the full app shell works offline. AI features (PDF import, chat) still need a network connection to reach your AI provider.</p><h2 id="guided-tour" tabindex="-1">Guided Tour <a class="header-anchor" href="#guided-tour" aria-label="Permalink to &quot;Guided Tour&quot;">​</a></h2><p>When you open the app for the first time, a 7-step spotlight tour walks you through the key areas of the interface — the import drop zone, category navigation, lifestyle context cards, settings, and the AI chat panel. Use the <strong>Next</strong> button to advance, or press <strong>Escape</strong> to dismiss.</p><p>You can replay the tour at any time from <strong>Settings → Display → Take a Tour</strong>.</p><h2 id="first-steps" tabindex="-1">First Steps <a class="header-anchor" href="#first-steps" aria-label="Permalink to &quot;First Steps&quot;">​</a></h2><h3 id="_1-configure-an-ai-provider" tabindex="-1">1. Configure an AI Provider <a class="header-anchor" href="#_1-configure-an-ai-provider" aria-label="Permalink to &quot;1. Configure an AI Provider&quot;">​</a></h3><p>PDF import, the AI chat panel, and several dashboard features require an AI provider. Open <strong>Settings</strong> (gear icon in the header) and go to the <strong>AI Provider</strong> tab.</p><p>See the <a href="./ai-providers.html">AI Providers</a> page for a full comparison and setup instructions for each option.</p><div class="tip custom-block"><p class="custom-block-title">No provider needed for most features</p><p>Charts, manual entry, JSON import/export, data tables, trend alerts, and correlations all work without any AI provider configured.</p></div><h3 id="_2-set-your-profile" tabindex="-1">2. Set Your Profile <a class="header-anchor" href="#_2-set-your-profile" aria-label="Permalink to &quot;2. Set Your Profile&quot;">​</a></h3><p>In <strong>Settings → Profile</strong>, enter your biological sex and date of birth. These affect:</p><ul><li>Reference ranges for sex-specific markers (hormones, hematology)</li><li>PhenoAge (biological age) calculation, which requires your DOB</li><li>Menstrual cycle tracking (available for female profiles)</li></ul><h3 id="_3-import-your-first-lab-report" tabindex="-1">3. Import Your First Lab Report <a class="header-anchor" href="#_3-import-your-first-lab-report" aria-label="Permalink to &quot;3. Import Your First Lab Report&quot;">​</a></h3><p>Drag and drop any lab PDF onto the drop zone at the top of the dashboard. The AI reads the report, maps results to known biomarkers, and shows you a preview before saving anything.</p><p>If you don&#39;t have a PDF handy, use <strong>Manual Entry</strong> to type in values directly.</p><div class="warning custom-block"><p class="custom-block-title">AI provider required for PDF import</p><p>You must have an AI provider configured before dropping a PDF. If the drop zone shows a prompt to set up a provider, visit Settings first.</p></div><p>Once data is imported, charts and analysis appear automatically across all 16 biomarker categories.</p>',28)])])}const g=t(s,[["render",i]]);export{c as __pageData,g as default};
